<template><div class="grid"><section class="galaxy-card span7"><h3 class="section-title">文本转语音</h3><el-form label-position="top" class="form-grid"><el-form-item label="选择声音模型"><el-select v-model="form.voice_model_id" placeholder="选择已就绪声音" style="width:100%"><el-option v-for="v in voices" :key="v.id" :label="v.name+' / '+v.status" :value="v.id" :disabled="v.status!=='就绪'" /></el-select></el-form-item><el-form-item label="合成文本"><el-input v-model="form.text_content" type="textarea" :rows="8" maxlength="1200" show-word-limit /></el-form-item><div class="grid"><el-form-item class="span4" label="语速"><el-slider v-model="form.speed" :min="-500" :max="500" /></el-form-item><el-form-item class="span4" label="音调"><el-slider v-model="form.pitch" :min="-500" :max="500" /></el-form-item><el-form-item class="span4" label="音量"><el-slider v-model="form.volume" :min="0" :max="100" /></el-form-item></div><div><el-button type="primary" size="large" :loading="loading" @click="convert">生成语音</el-button><el-button @click="demoText">插入直播话术</el-button></div></el-form></section><section class="galaxy-card span5"><h3 class="section-title">效果预览</h3><div class="audio-preview"><el-empty v-if="!audioUrl" description="生成后在这里试听"/><template v-else><audio :src="audioUrl" controls style="width:100%"></audio><p class="muted">任务状态：{{status}}</p><el-button type="success" @click="download">下载音频</el-button></template></div><div class="script-card"><b>接口说明</b><p class="muted">POST /api/tts/convert，支持 voice_model_id、text_content、speed、pitch、volume。</p></div></section></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { getVoiceList } from '@/api/voice';import { convertTTS } from '@/api/tts';const voices=ref([]),loading=ref(false),audioUrl=ref(''),status=ref('未开始');const form=reactive({voice_model_id:null,text_content:'欢迎来到直播间，今天为大家准备了限时专属福利。',speed:0,pitch:0,volume:80});onMounted(async()=>{voices.value=await getVoiceList();form.voice_model_id=voices.value.find(v=>v.status==='就绪')?.id});function demoText(){form.text_content='家人们，左上角福袋已经开启，喜欢的朋友先点关注，稍后还有专属优惠。'}function mediaUrl(v){if(!v)return'';if(/^(https?:|blob:|data:)/.test(v))return v;return (import.meta.env.VITE_API_BASE||'/api')+(String(v).startsWith('/')?v:'/'+v)}async function convert(){if(!form.voice_model_id||!form.text_content)return ElMessage.warning('请选择声音并输入文本');loading.value=true;try{const res=await convertTTS({...form,voiceModelId:form.voice_model_id,textContent:form.text_content});audioUrl.value=mediaUrl(res.audioUrl||res.audio_url||res.audioOutputPath||res.audio_output_path||res.url);status.value=res.status||'完成';ElMessage.success('合成完成')}finally{loading.value=false}}function download(){const a=document.createElement('a');a.href=audioUrl.value;a.download='tts-output.mp3';a.click()}</script>
